var webView: StageWebView = new StageWebView();
var initialized = false;

function stageWebViewGif(localFileName:String):void {
    webView.stage = this.stage;
    if (webView.viewPort) {
        webView.viewPort = null;
    }
    if (!initialized) {
        initialized = true;
    }

    if (stage.nativeWindow.displayState == NativeWindowDisplayState.MAXIMIZED) {
        webView.viewPort = new Rectangle(760, 250, 400, 270);
    } else {
        webView.viewPort = new Rectangle(120, 300, 480, 340);
    }

    var filePath:String = File.applicationDirectory.nativePath + "/" + localFileName;
    var fileURL:String = "file:///" + filePath.replace(/\\/g, "/");
    webView.loadURL(fileURL);
}

webView.stage = null;
webView.viewPort = null;

stage.nativeWindow.addEventListener(NativeWindowDisplayStateEvent.DISPLAY_STATE_CHANGE, onStateChange);
function onStateChange(e:NativeWindowDisplayStateEvent):void {
    if (e.afterDisplayState == NativeWindowDisplayState.MAXIMIZED) {
		webView.viewPort = null;
		webView.viewPort = new Rectangle(760, 250, 400, 270);
    } else {
        webView.viewPort = new Rectangle(120, 300, 480, 340);
    }
}

function togglePlayPause(e:MouseEvent):void {
    if (isSoundPlaying) {
        if (soundChannel != null) {
            pausePosition = soundChannel.position;
            soundChannel.stop();
            soundChannel = null;
        }
		playBtn.gotoAndStop(1);
        isSoundPlaying = false;
    } else {
        if (pausePosition >= soundLength) {
            pausePosition = 0;
        }
        soundChannel = backsound.play(pausePosition);
		playBtn.gotoAndStop(2);
        isSoundPlaying = true;
        soundChannel.addEventListener(Event.SOUND_COMPLETE, onSoundComplete);
    }
}

function onSoundComplete(e:Event):void {
    soundChannel.removeEventListener(Event.SOUND_COMPLETE, onSoundComplete);
    soundChannel = null;
    isSoundPlaying = false;
    pausePosition = 0;
    progressBar.scaleX = 0;
    currentTime_txt.text = formatTime(0);
}

function updateProgress(e:Event):void {
    if (isSoundPlaying && soundChannel != null) {
        var pos:Number = soundChannel.position;
        if (soundLength > 0) {
            var percent:Number = pos / soundLength;
			var maxPercent:Number = Math.min(0.86, percent);
            percent = Math.min(1, Math.max(0, maxPercent));
            progressBar.scaleX = percent;
        }

        currentTime_txt.text = formatTime(pos);
    }
}

function formatTime(ms:Number):String {
    var seconds:Number = Math.floor(ms / 1000);
    var minutes:Number = Math.floor(seconds / 60);
    seconds = seconds % 60;

    var secStr:String = (seconds < 10) ? "0" + seconds : String(seconds);
    return minutes + ":" + secStr;
}

function cleanUpSound():void {
    if (soundChannel) {
        soundChannel.stop();
        soundChannel.removeEventListener(Event.SOUND_COMPLETE, onSoundComplete);
    }
    removeEventListener(Event.ENTER_FRAME, updateProgress);
	if (playBtn) {
		playBtn.gotoAndStop(1);
		playBtn.removeEventListener(MouseEvent.CLICK, togglePlayPause);
	}
}

